"use strict";const e=require("../request.js");exports.getGlobalNews=function(t=!1,n=!1,o=60){const i=`mode=global&important=${n}&limit=${o}${t?"&force=true":""}`;return e.get(`/api/fund/news?${i}`,{loadingText:"读取资讯",fallbackData:{items:[]}})},exports.getHoldingNews=function(t,n=!1,o=!1,i=40){const a=`username=${encodeURIComponent(t)}&important=${o}&limit=${i}${n?"&force=true":""}`;return e.get(`/api/fund/holding-news?${a}`,{loadingText:"读取持仓资讯",fallbackData:{items:[]}})};
